import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract_packages(data):
    result = {}
    for project in data.get('projects', []):
        pname = project['path'].split('/')[-1]
        pkgs = {}
        for fw in project.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (pkg['id'], tfm)
                pkgs[key] = pkg['resolvedVersion']
        result[pname] = pkgs
    return result

b = extract_packages(baseline)
a = extract_packages(after)

changes = []
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for key in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(key)
        av = ap.get(key)
        if bv != av:
            changes.append((proj, key[0], key[1], bv, av))

if changes:
    print('VERSION CHANGES:')
    for proj, pkg, tfm, bv, av in changes:
        print(f'  {proj} | {pkg} ({tfm}): {bv} -> {av}')
else:
    print('No version changes detected - conversion is version-neutral for top-level packages.')
"

